INSERT OR IGNORE INTO Articles (text, category_id) VALUES (')            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 177/2001, de 4 de Junho   - Declaração n.º 13-T/2001, de 30 de Junho   - Lei n.º 60/2007, de 04 de Setembro   - DL n.º 26/2010, de 30 de Março   - DL n.º 136/2014, de 09 de Setembro   - DL n.º 10/2024, de 08 de Janeiro
